import React, { useEffect, useState } from "react";
import { getFreelancerDashboard } from "../../api/api";
import { useNavigate } from "react-router-dom";

const fmt = (d) => d ? new Date(d).toLocaleDateString("en-IN", { day: "2-digit", month: "short", year: "numeric" }) : "";

const S = {
  page: { background: "#0f172a", minHeight: "100vh", padding: "32px", fontFamily: "'Segoe UI', sans-serif" },
  header: { marginBottom: "32px" },
  greeting: { fontSize: "26px", fontWeight: "700", color: "#f1f5f9", letterSpacing: "-0.5px" },
  sub: { fontSize: "14px", color: "#64748b", marginTop: "4px" },
  grid4: { display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: "16px", marginBottom: "28px" },
  card: (accent) => ({
    background: "linear-gradient(135deg, #1e293b, #0f172a)",
    border: `1px solid ${accent}30`,
    borderRadius: "14px", padding: "20px",
    borderTop: `3px solid ${accent}`,
  }),
  cardLabel: { fontSize: "11px", fontWeight: "600", color: "#64748b", textTransform: "uppercase", letterSpacing: "1px", marginBottom: "8px" },
  cardValue: (color) => ({ fontSize: "28px", fontWeight: "800", color }),
  cardSub: { fontSize: "11px", color: "#475569", marginTop: "4px" },
  section: { background: "#1e293b", border: "1px solid #334155", borderRadius: "16px", overflow: "hidden" },
  sectionHead: { display: "flex", justifyContent: "space-between", alignItems: "center", padding: "18px 22px", borderBottom: "1px solid #334155" },
  sectionTitle: { fontSize: "15px", fontWeight: "700", color: "#f1f5f9" },
  browseBtn: { fontSize: "12px", fontWeight: "600", color: "#2dd4bf", background: "rgba(45,212,191,0.08)", border: "1px solid rgba(45,212,191,0.2)", borderRadius: "8px", padding: "6px 14px", cursor: "pointer" },
  row: { display: "flex", justifyContent: "space-between", alignItems: "center", padding: "16px 22px", borderBottom: "1px solid #1e293b", transition: "background 0.15s" },
  projectTitle: { fontSize: "14px", fontWeight: "600", color: "#e2e8f0" },
  projectMeta: { fontSize: "12px", color: "#64748b", marginTop: "3px" },
  badge: (s) => {
    const map = { accepted: ["#d1fae5","#065f46"], rejected: ["#fee2e2","#991b1b"], pending: ["#fef3c7","#92400e"] };
    const [bg, text] = map[s] || map.pending;
    return { background: bg, color: text, fontSize: "10px", fontWeight: "700", padding: "3px 10px", borderRadius: "20px", textTransform: "capitalize" };
  },
  empty: { textAlign: "center", padding: "48px", color: "#475569" },
  emptyIcon: { fontSize: "36px", marginBottom: "8px" },
};

export default function FreelancerDashboard() {
  const user = JSON.parse(localStorage.getItem("user") || "{}");
  const navigate = useNavigate();
  const [data, setData] = useState({ activeProjects: 0, pendingProposals: 0, projects: [] });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getFreelancerDashboard().then(r => { setData(r.data); setLoading(false); }).catch(() => setLoading(false));
  }, []);

  if (loading) return <div style={{ ...S.page, display:"flex", alignItems:"center", justifyContent:"center" }}><div style={{ color:"#2dd4bf", fontSize:"16px" }}>Loading...</div></div>;

  const accepted = data.projects?.filter(p => p.proposal_status === "accepted").length || 0;

  return (
    <div style={S.page}>
      <div style={S.header}>
        <h1 style={S.greeting}>Welcome back, {user.name} 👋</h1>
        <p style={S.sub}>Here's your freelancing overview</p>
      </div>

      <div style={S.grid4}>
        {[
          { label: "Applied Projects", value: data.activeProjects, color: "#38bdf8", accent: "#38bdf8", sub: "Total applied" },
          { label: "Total Proposals", value: data.pendingProposals, color: "#a78bfa", accent: "#a78bfa", sub: "Submitted" },
          { label: "Accepted", value: accepted, color: "#4ade80", accent: "#4ade80", sub: "Projects won" },
          { label: "Account", value: "Freelancer", color: "#2dd4bf", accent: "#2dd4bf", sub: user.email?.slice(0,20) },
        ].map((c, i) => (
          <div key={i} style={S.card(c.accent)}>
            <p style={S.cardLabel}>{c.label}</p>
            <p style={S.cardValue(c.color)}>{c.value}</p>
            <p style={S.cardSub}>{c.sub}</p>
          </div>
        ))}
      </div>

      <div style={S.section}>
        <div style={S.sectionHead}>
          <span style={S.sectionTitle}>Projects You Applied To</span>
          <button style={S.browseBtn} onClick={() => navigate("/freelancer/find-projects")}>Browse Projects →</button>
        </div>
        {(!data.projects || data.projects.length === 0) ? (
          <div style={S.empty}><div style={S.emptyIcon}>🔍</div><p>No projects yet. Start browsing!</p></div>
        ) : (
          data.projects.map((p) => (
            <div key={p.id} style={S.row}>
              <div>
                <p style={S.projectTitle}>{p.title}</p>
                <p style={S.projectMeta}>{p.description?.slice(0,70)}... · Budget: ₹{p.budget}{p.my_bid ? ` · Your Bid: ₹${p.my_bid}` : ""}{p.deadline ? ` · 📅 ${fmt(p.deadline)}` : ""}</p>
              </div>
              {p.proposal_status && <span style={S.badge(p.proposal_status)}>{p.proposal_status}</span>}
            </div>
          ))
        )}
      </div>
    </div>
  );
}
